const fs=require("fs"),path=require("path"),readline=require("readline-sync");function nameCleaning(e){let n=e.replace(/[^A-Za-z0-9 ]+/g," ");return n=n.replace(/\s+/g,"-"),n.toLowerCase()}function slugify(e){return e.toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/(^-|-$)/g,"")}function createAuthor(e,n,o,t){const i=slugify(e),r=path.join(process.cwd(),"content","authors",i);if(fs.existsSync(r))return console.log(`⚠️  L'autore ${e} esiste già!`),!1;fs.mkdirSync(r,{recursive:!0});const l=`---\ntitle: "${e}"\nname: "${e}"\nrole: "${n}"\navatar: "images/${t}"\nbio: ""\nlinks:\n  - label: "Linkedin"\n    url: "${o}"\n---`;return fs.writeFileSync(path.join(r,"_index.md"),l,"utf-8"),console.log(`✅ Autore creato: ${e} (${i})`),!0}function addToAbout(e,n,o,t){const i=path.join(process.cwd(),"content","about","index.md");if(!fs.existsSync(i))return console.log("❌ File about non trovato!"),!1;slugify(e),o.replace("https://www.linkedin.com/in/","");const r=`{{< about-section\n    title="${e}"\n    content="${n}"\n    imgSrc="images/${t}"\n    button_url="${o}"\n  >}}`;return fs.readFile(i,"utf-8",(n,o)=>{if(n)return void console.log("❌ Errore nella lettura del file:",n.message);const t=o.split("\n");let l=t.length;for(let e=t.length-1;e>=0;e--)if("{{< /about-section >}}"===t[e].trim()){l=e+1;break}t.splice(l,0,r),fs.writeFileSync(i,t.join("\n"),"utf-8"),console.log(`✅ Aggiunto a about us: ${e}`)}),!0}function main(){console.log("\n=== 🧑‍💼 CREAZIONE NUOVO MEMBRO TEAM ===\n");const e=readline.question("Nome e cognome: ");if(!e.trim())return void console.log("❌ Il nome è obbligatorio!");const n=readline.question("Ruolo (es: Sviluppatore Full-Stack): "),o=readline.question("URL LinkedIn (es: https://www.linkedin.com/in/...): "),t=readline.question("Nome file immagine (es: nome.jpg): "),i=readline.question("\nCreare solo l'autore? (s/n, default n): "),r=createAuthor(e,n,o,t);if("s"!==i.toLowerCase()){if(r){"s"===readline.question("Aggiungere anche a About Us? (s/n): ").toLowerCase()&&addToAbout(e,n,o,t)}console.log("\n✅ Operazione completata!")}else console.log("\n✅ Operazione completata!")}main();